#!/usr/bin/env python3
"""Verify one scratch-modified fan-out item without model judgment."""

from __future__ import annotations

import argparse
import ast
import pathlib
import re
import subprocess
import sys
from typing import Any

SCRIPT_DIR = pathlib.Path(__file__).resolve().parent
if str(SCRIPT_DIR) not in sys.path:
    sys.path.insert(0, str(SCRIPT_DIR))

from fanout_common import (  # noqa: E402
    item_file,
    params_for,
    parse_source,
    qualname_targets,
    read_json,
    strip_docstrings,
    write_json,
)

PLACEHOLDER_RE = re.compile(r"\b(todo|tbd|fixme|placeholder)\b", re.IGNORECASE)


def fail(check: str, reason: str) -> dict[str, Any]:
    return {"passed": False, "failed_check": check, "reason": reason}


def ok() -> dict[str, Any]:
    return {"passed": True, "failed_check": None, "reason": None}


def compile_check(path: pathlib.Path) -> tuple[bool, str]:
    result = subprocess.run(
        [sys.executable, "-m", "py_compile", str(path)],
        capture_output=True,
        text=True,
    )
    return result.returncode == 0, (result.stdout + result.stderr).strip()


def word_present(text: str, name: str) -> bool:
    return re.search(rf"(?<![A-Za-z0-9_]){re.escape(name)}(?![A-Za-z0-9_])", text) is not None


def verify(corpus: pathlib.Path, item: dict[str, Any], modified_path: pathlib.Path, insertion_rc: int = 0) -> dict[str, Any]:
    if insertion_rc != 0:
        return fail("insertion_clean", f"insert_docstrings.py exited {insertion_rc}")
    passed_compile, compile_output = compile_check(modified_path)
    if not passed_compile:
        return fail("compiles", compile_output or "py_compile failed")

    pristine_path = item_file(corpus, item)
    pristine_source = pristine_path.read_text(encoding="utf-8")
    modified_source = modified_path.read_text(encoding="utf-8")
    pristine_tree = parse_source(pristine_source, item["path"])
    modified_tree = parse_source(modified_source, str(modified_path))
    pristine_targets = qualname_targets(pristine_tree)

    coverage_missing = []
    pristine_nodes = collect_nodes_multi(pristine_tree)
    modified_nodes = collect_nodes_multi(modified_tree)
    for qualname in item["targets"]:
        pairs = list(zip(pristine_nodes.get(qualname, []), modified_nodes.get(qualname, [])))
        missing_pairs = [pair for pair in pairs if ast.get_docstring(pair[0], clean=False) is None]
        if not missing_pairs or any(ast.get_docstring(modified, clean=False) is None for _pristine, modified in missing_pairs):
            coverage_missing.append(qualname)
    if coverage_missing:
        return fail("coverage", "missing inserted docstrings: " + ", ".join(coverage_missing))

    stripped_pristine = ast.dump(strip_docstrings(pristine_tree), include_attributes=False)
    stripped_modified = ast.dump(strip_docstrings(modified_tree), include_attributes=False)
    if stripped_pristine != stripped_modified:
        return fail("ast_equivalence", "AST differs after stripping docstrings")

    for qualname in item["targets"]:
        pairs = list(zip(pristine_nodes.get(qualname, []), modified_nodes.get(qualname, [])))
        for pristine_node, modified_node in pairs:
            if ast.get_docstring(pristine_node, clean=False) is not None:
                continue
            docstring = ast.get_docstring(modified_node, clean=False) or ""
            if len(docstring.strip()) < 20 or PLACEHOLDER_RE.search(docstring):
                return fail("non_placeholder", f"{qualname} docstring is too short or placeholder-like")
            if isinstance(pristine_node, (ast.FunctionDef, ast.AsyncFunctionDef)):
                params = params_for(pristine_node)
                missing = [name for name in params if not word_present(docstring, name)]
                if missing:
                    return fail("parameter_mention", f"{qualname} missing parameter mention(s): {', '.join(missing)}")
    return ok()


def collect_nodes(tree: ast.AST) -> dict[str, ast.AST]:
    nodes: dict[str, ast.AST] = {}

    def walk_body(body: list[ast.stmt], stack: list[str]) -> None:
        for node in body:
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                qualname = ".".join([*stack, node.name])
                nodes[qualname] = node
                walk_body(node.body, [*stack, node.name])

    if isinstance(tree, ast.Module):
        walk_body(tree.body, [])
    return nodes


def collect_nodes_multi(tree: ast.AST) -> dict[str, list[ast.AST]]:
    nodes: dict[str, list[ast.AST]] = {}

    def walk_body(body: list[ast.stmt], stack: list[str]) -> None:
        for node in body:
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                qualname = ".".join([*stack, node.name])
                nodes.setdefault(qualname, []).append(node)
                walk_body(node.body, [*stack, node.name])

    if isinstance(tree, ast.Module):
        walk_body(tree.body, [])
    return nodes


def main() -> int:
    parser = argparse.ArgumentParser(description="Verify one fan-out item scratch file.")
    parser.add_argument("--corpus", required=True)
    parser.add_argument("--item", required=True)
    parser.add_argument("--modified", required=True)
    parser.add_argument("--out", required=True)
    parser.add_argument("--insertion-rc", type=int, default=0)
    args = parser.parse_args()

    item = read_json(pathlib.Path(args.item))
    result = verify(pathlib.Path(args.corpus), item, pathlib.Path(args.modified), args.insertion_rc)
    write_json(pathlib.Path(args.out), result)
    return 0 if result["passed"] else 1


if __name__ == "__main__":
    raise SystemExit(main())

#!/usr/bin/env python3
"""Shared helpers for the showcase fan-out docstring benchmark."""

from __future__ import annotations

import ast
import copy
import hashlib
import json
import pathlib
import subprocess
from dataclasses import dataclass
from datetime import datetime, timezone
from typing import Any, Iterable


CORPUS_URL = "https://github.com/scrapy/scrapy.git"
PINNED_SHA = "a8ffdcf8517a8973391a14635234b6993b15a86a"
DEFAULT_MODEL = "Qwen/Qwen3-30B-A3B-GPTQ-Int4"
DEFAULT_BASE_URL = "http://127.0.0.1:8091/v1"


@dataclass(frozen=True)
class Target:
    qualname: str
    kind: str
    lineno: int
    col_offset: int
    params: tuple[str, ...]


def now_iso() -> str:
    return datetime.now(timezone.utc).astimezone().isoformat(timespec="milliseconds")


def sha256_text(text: str) -> str:
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def read_json(path: pathlib.Path) -> Any:
    return json.loads(path.read_text(encoding="utf-8"))


def write_json(path: pathlib.Path, value: Any) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(json.dumps(value, indent=2, sort_keys=True) + "\n", encoding="utf-8")


def repo_head(corpus: pathlib.Path) -> str:
    result = subprocess.run(
        ["git", "-C", str(corpus), "rev-parse", "HEAD"],
        capture_output=True,
        text=True,
        check=True,
    )
    return result.stdout.strip()


def verify_corpus_head(corpus: pathlib.Path) -> None:
    head = repo_head(corpus)
    if head != PINNED_SHA:
        raise SystemExit(f"corpus HEAD {head} != pinned {PINNED_SHA}")


def generator_git_sha(repo_root: pathlib.Path) -> str | None:
    result = subprocess.run(
        ["git", "-C", str(repo_root), "rev-parse", "HEAD"],
        capture_output=True,
        text=True,
    )
    return result.stdout.strip() if result.returncode == 0 else None


def public_name(name: str) -> bool:
    return not name.startswith("_")


def params_for(node: ast.FunctionDef | ast.AsyncFunctionDef) -> tuple[str, ...]:
    args = node.args
    names: list[str] = []
    names.extend(arg.arg for arg in args.posonlyargs)
    names.extend(arg.arg for arg in args.args)
    if args.vararg is not None:
        names.append(args.vararg.arg)
    names.extend(arg.arg for arg in args.kwonlyargs)
    if args.kwarg is not None:
        names.append(args.kwarg.arg)
    return tuple(name for name in names if name not in {"self", "cls"})


def qualname_targets(tree: ast.AST) -> dict[str, Target]:
    targets: dict[str, Target] = {}

    def visit_body(body: Iterable[ast.stmt], stack: list[str]) -> None:
        for node in body:
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                qualname = ".".join([*stack, node.name])
                if public_name(node.name) and ast.get_docstring(node, clean=False) is None:
                    if isinstance(node, ast.ClassDef):
                        targets[qualname] = Target(qualname, "class", node.lineno, node.col_offset, ())
                    else:
                        targets[qualname] = Target(
                            qualname,
                            "function",
                            node.lineno,
                            node.col_offset,
                            params_for(node),
                        )
                visit_body(node.body, [*stack, node.name])

    if not isinstance(tree, ast.Module):
        return targets
    visit_body(tree.body, [])
    return targets


def parse_source(source: str, filename: str = "<source>") -> ast.Module:
    return ast.parse(source, filename=filename)


def item_file(corpus: pathlib.Path, item: dict[str, Any]) -> pathlib.Path:
    rel = pathlib.PurePosixPath(item["path"])
    if rel.is_absolute() or ".." in rel.parts:
        raise ValueError(f"unsafe item path: {item['path']}")
    path = (corpus / pathlib.Path(*rel.parts)).resolve()
    corpus_resolved = corpus.resolve()
    if path != corpus_resolved and corpus_resolved not in path.parents:
        raise ValueError(f"item path escapes corpus: {item['path']}")
    return path


def strip_docstrings(tree: ast.AST) -> ast.AST:
    class Stripper(ast.NodeTransformer):
        def strip_body(self, node: ast.Module | ast.ClassDef | ast.FunctionDef | ast.AsyncFunctionDef):
            self.generic_visit(node)
            if node.body and isinstance(node.body[0], ast.Expr):
                value = node.body[0].value
                if isinstance(value, ast.Constant) and isinstance(value.value, str):
                    node.body = node.body[1:]
            return node

        def visit_Module(self, node: ast.Module):
            return self.strip_body(node)

        def visit_ClassDef(self, node: ast.ClassDef):
            return self.strip_body(node)

        def visit_FunctionDef(self, node: ast.FunctionDef):
            return self.strip_body(node)

        def visit_AsyncFunctionDef(self, node: ast.AsyncFunctionDef):
            return self.strip_body(node)

    return ast.fix_missing_locations(Stripper().visit(copy.deepcopy(tree)))


def sorted_item_paths(items_dir: pathlib.Path) -> list[pathlib.Path]:
    return sorted(items_dir.glob("item-*.json"))


def v1_url(base: str, path: str) -> str:
    base = base.rstrip("/")
    if base.endswith("/v1"):
        return base + path
    return base + "/v1" + path


def extract_json_object(text: str) -> dict[str, Any]:
    try:
        parsed = json.loads(text)
    except json.JSONDecodeError:
        parsed = json.loads(first_balanced_json_object(text))
    if not isinstance(parsed, dict):
        raise ValueError("assistant response is not a JSON object")
    docstrings = parsed.get("docstrings")
    if (
        docstrings is None
        and parsed
        and all(isinstance(key, str) and isinstance(value, str) for key, value in parsed.items())
    ):
        docstrings = parsed
    if not isinstance(docstrings, dict):
        raise ValueError("assistant response missing docstrings object")
    for key, value in docstrings.items():
        if not isinstance(key, str) or not isinstance(value, str):
            raise ValueError("docstrings must map strings to strings")
    return {"docstrings": docstrings}


def first_balanced_json_object(text: str) -> str:
    start = text.find("{")
    if start == -1:
        raise json.JSONDecodeError("no JSON object found", text, 0)

    depth = 0
    in_string = False
    escaped = False
    for index in range(start, len(text)):
        char = text[index]
        if in_string:
            if escaped:
                escaped = False
            elif char == "\\":
                escaped = True
            elif char == '"':
                in_string = False
            continue
        if char == '"':
            in_string = True
        elif char == "{":
            depth += 1
        elif char == "}":
            depth -= 1
            if depth == 0:
                return text[start : index + 1]
    raise json.JSONDecodeError("unterminated JSON object", text, start)


def normalize_docstring_keys(docstrings: dict[str, str], expected: Iterable[str]) -> dict[str, str]:
    expected_list = list(expected)
    expected_set = set(expected_list)
    normalized: dict[str, str] = {}
    source_keys: dict[str, str] = {}

    for key, value in docstrings.items():
        if key in expected_set:
            matches = [key]
        else:
            matches = [qualname for qualname in expected_list if key.endswith("." + qualname)]
        if not matches:
            raise ValueError(f"extra docstrings for: {key}")
        if len(matches) > 1:
            raise ValueError(
                f"ambiguous docstring key {key!r} matches: {', '.join(sorted(matches))}"
            )
        qualname = matches[0]
        if qualname in normalized:
            raise ValueError(
                f"ambiguous docstring keys for {qualname}: {source_keys[qualname]!r}, {key!r}"
            )
        normalized[qualname] = value
        source_keys[qualname] = key

    missing = sorted(expected_set - set(normalized))
    if missing:
        raise ValueError(f"missing docstrings for: {', '.join(missing)}")
    return normalized


def write_tokens(out: pathlib.Path, responses: list[dict[str, Any]]) -> None:
    total_prompt = 0
    total_completion = 0
    requests = []
    for i, body in enumerate(responses, 1):
        usage = body.get("usage") or {}
        prompt = usage.get("prompt_tokens") or 0
        completion = usage.get("completion_tokens") or 0
        total_prompt += prompt
        total_completion += completion
        requests.append(
            {
                "request_index": i,
                "prompt_tokens": prompt,
                "completion_tokens": completion,
                "client_wall_s": body.get("_client_wall_s"),
                "timings": body.get("timings") or None,
            }
        )
    write_json(
        out / "tokens.json",
        {
            "prompt_tokens": total_prompt,
            "completion_tokens": total_completion,
            "total_tokens": total_prompt + total_completion,
            "requests": requests,
        },
    )

